"""All final figures, generated by script from stored result JSONs.

Design rules (dataviz skill): single axis per panel (small multiples instead
of dual axes), fixed categorical color assignment (a variant keeps its color
in every figure), recessive grids, legends for multi-series panels.
"""

from __future__ import annotations

import json
import logging
from pathlib import Path

import numpy as np

log = logging.getLogger(__name__)

# Fixed palette (dataviz reference, light surface). Color follows the entity.
C_NO_PSI = "#2a78d6"     # blue — without-PSI variants
C_WITH_PSI = "#1baf7a"   # aqua — with-PSI variants
C_BASELINE = "#eda100"   # yellow — persistence/heuristic
C_MODE = {"fixed": "#52514e", "percentile": "#eda100", "senpai": "#4a3aa7",
          "learned_no_psi": "#2a78d6", "learned_with_psi": "#1baf7a"}
C_TEXT = "#52514e"
C_GRID = "#e6e5e0"
C_CRITICAL = "#d03b3b"


def _style(ax, title=None, xlabel=None, ylabel=None):
    ax.grid(True, color=C_GRID, linewidth=0.5)
    ax.set_axisbelow(True)
    for spine in ("top", "right"):
        ax.spines[spine].set_visible(False)
    if title:
        ax.set_title(title, fontsize=10)
    if xlabel:
        ax.set_xlabel(xlabel, fontsize=9)
    if ylabel:
        ax.set_ylabel(ylabel, fontsize=9)


def _save(fig, out_path: Path):
    out_path.parent.mkdir(parents=True, exist_ok=True)
    fig.tight_layout()
    fig.savefig(out_path, dpi=150)
    import matplotlib.pyplot as plt

    plt.close(fig)
    log.info("figure: %s", out_path)


def fig_representative_runs(raw_dir: Path, run_ids: list[str], out_path: Path):
    """Reuses the calibration plot (usage + PSI panels) per run."""
    from psi_memory.environment.calibration import load_run, plot_run

    for run_id in run_ids:
        plot_run(load_run(raw_dir / run_id),
                 out_path / f"timeseries_{run_id}.png")


def fig_psi_vs_usage(raw_dir: Path, quiet_run: str, pressured_run: str,
                     out_path: Path):
    """The core ambiguity: similar usage, opposite pressure (2x2 panels)."""
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    from psi_memory.environment.calibration import load_run

    runs = [load_run(raw_dir / quiet_run), load_run(raw_dir / pressured_run)]
    # sharey per row: without it the quiet panel autoscales its flat-zero PSI
    # into apparent activity — the comparison must share scales to be honest.
    fig, axes = plt.subplots(2, 2, figsize=(10, 5.5), sharex="col", sharey="row")
    for col, run in enumerate(runs):
        ratio = [c / run.limit_mib * 100 for c in run.current_mib]
        axes[0][col].plot(run.t, ratio, color=C_NO_PSI, linewidth=2)
        axes[0][col].axhline(100, color=C_TEXT, linewidth=1, linestyle="--")
        axes[0][col].set_ylim(0, 115)
        _style(axes[0][col], title=f"{run.workload} ({run.run_id.split('-')[0]})",
               ylabel="usage % of limit" if col == 0 else None)
        axes[1][col].plot(run.t, run.some_avg10, color=C_WITH_PSI, linewidth=2)
        _style(axes[1][col], xlabel="elapsed (s)",
               ylabel="PSI some avg10 %" if col == 0 else None)
        axes[1][col].set_ylim(bottom=0)
    fig.suptitle("Same high usage — opposite pressure", fontsize=11)
    _save(fig, out_path)


def fig_ablation_bars(heldout_report: dict, out_path: Path):
    """MAE per model, no-PSI vs with-PSI, seed spread as error bars."""
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    rows = heldout_report["summary"]
    models = ["persistence", "heuristic", "rf", "xgb", "lstm"]
    present = [m for m in models
               if any(r["model"] == m for r in rows)]
    fig, ax = plt.subplots(figsize=(8, 4.2))
    width = 0.38
    for offset, variant, color, label in (
            (-width / 2, "no_psi", C_NO_PSI, "without PSI"),
            (width / 2, "with_psi", C_WITH_PSI, "with PSI")):
        xs, ys, errs = [], [], []
        for i, model in enumerate(present):
            row = next((r for r in rows if r["model"] == model
                        and r["variant"] in (variant, "n/a")), None)
            if row is None:
                continue
            stats = row["test_mae_across_seeds"]
            if row["variant"] == "n/a" and variant == "with_psi":
                continue  # baselines drawn once, on the no-PSI slot
            xs.append(i + (0 if row["variant"] == "n/a" else offset))
            ys.append(stats["mean"])
            errs.append(stats["std"])
        color_used = C_BASELINE if variant == "no_psi" and False else color
        ax.bar(xs, ys, width=width, color=color_used, label=label,
               yerr=errs, capsize=3, error_kw={"ecolor": C_TEXT})
    ax.set_xticks(range(len(present)))
    ax.set_xticklabels(present)
    ax.set_yscale("log")
    _style(ax, title="Held-out test MAE by model and PSI variant "
                     "(log scale; error bars = seed std)",
           ylabel="test MAE (MiB, log)")
    ax.legend(fontsize=8, framealpha=0.9)
    _save(fig, out_path)


def fig_pred_vs_actual(heldout_report: dict, model: str, variant: str,
                       out_path: Path):
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    row = next(r for r in heldout_report["summary"]
               if r["model"] == model and r["variant"] == variant
               and r.get("predictions"))
    preds = row["predictions"]
    y_true = np.asarray(preds["y_true"])
    y_pred = np.asarray(preds["y_pred"])
    fig, ax = plt.subplots(figsize=(5.4, 5))
    lim = [0, max(y_true.max(), y_pred.max()) * 1.05]
    ax.plot(lim, lim, color=C_TEXT, linewidth=1, linestyle="--", label="y = x")
    ax.scatter(y_true, y_pred, s=8, alpha=0.35,
               color=C_WITH_PSI if variant == "with_psi" else C_NO_PSI,
               edgecolors="none")
    ax.set_xlim(lim), ax.set_ylim(lim)
    _style(ax, title=f"Predicted vs actual future peak — {model} ({variant})",
           xlabel="actual peak (MiB)", ylabel="predicted peak (MiB)")
    ax.legend(fontsize=8)
    _save(fig, out_path)


def fig_error_cdf(heldout_report: dict, out_path: Path):
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    fig, ax = plt.subplots(figsize=(7, 4.2))
    for row in heldout_report["summary"]:
        preds = row.get("predictions")
        if not preds:
            continue
        errors = np.sort(np.abs(np.asarray(preds["y_true"])
                                - np.asarray(preds["y_pred"])))
        cdf = np.arange(1, len(errors) + 1) / len(errors)
        variant = row["variant"]
        color = (C_BASELINE if variant == "n/a"
                 else C_WITH_PSI if variant == "with_psi" else C_NO_PSI)
        style = {"persistence": ":", "heuristic": "--"}.get(row["model"], "-")
        if row["model"] == "rf":
            style = "-."
        ax.plot(errors, cdf, linewidth=1.8, linestyle=style, color=color,
                label=f"{row['model']}/{variant}")
    ax.set_xscale("log")
    _style(ax, title="Per-window absolute error CDF (held-out test)",
           xlabel="|error| (MiB, log)", ylabel="fraction of windows")
    ax.legend(fontsize=7, framealpha=0.9, ncol=2)
    _save(fig, out_path)


def fig_importances(heldout_metrics_dir: Path, dataset_name: str,
                    out_path: Path, top_k: int = 14):
    """Top feature importances from the newest per-seed rf with_psi result."""
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    reports = sorted(heldout_metrics_dir.glob("per_seed/ablation_*.json"))
    for report_path in reversed(reports):
        report = json.loads(report_path.read_text(encoding="utf-8"))
        row = next((r for r in report["results"] if r["model"] == "rf"
                    and r["variant"] == "with_psi"
                    and r.get("feature_importances")), None)
        if row:
            break
    else:
        raise FileNotFoundError("no rf/with_psi importances found")
    items = list(row["feature_importances"].items())[:top_k][::-1]
    names = [name for name, _ in items]
    values = [value for _, value in items]
    colors = [C_WITH_PSI if name.startswith("psi_") else C_NO_PSI
              for name in names]
    fig, ax = plt.subplots(figsize=(7, 4.8))
    ax.barh(names, values, color=colors)
    _style(ax, title="Random Forest feature importances (with-PSI variant); "
                     "PSI features in green",
           xlabel="importance")
    ax.tick_params(axis="y", labelsize=7)
    _save(fig, out_path)


def fig_tradeoff(closed_loop_report: dict, out_path: Path):
    """OOM/demand-above-limit vs wasted headroom, per mode across margins."""
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    sessions = [s for s in closed_loop_report["sessions"]
                if s.get("avg_headroom_mib") is not None]
    scenarios = sorted({s["scenario"] for s in sessions})
    fig, axes = plt.subplots(1, len(scenarios), figsize=(11, 4.4), sharey=True)
    if len(scenarios) == 1:
        axes = [axes]
    for ax, scenario in zip(axes, scenarios):
        for label in sorted({s["label"] for s in sessions}):
            points = sorted(
                [s for s in sessions
                 if s["scenario"] == scenario and s["label"] == label],
                key=lambda s: (s["margin"] if s["margin"] is not None else 0))
            if not points:
                continue
            xs = [p["avg_headroom_mib"] for p in points]
            ys = [p["oom_kill_events"] + p["demand_above_limit_events"]
                  for p in points]
            color = C_MODE.get(label, C_TEXT)
            marker = "o" if len(points) > 1 else "s"
            ax.plot(xs, ys, marker=marker, markersize=6, linewidth=1.5,
                    color=color, label=label)
            for p, x, y in zip(points, xs, ys):
                if p["margin"] is not None:
                    ax.annotate(f"{p['margin']:.0%}", (x, y), fontsize=6,
                                color=C_TEXT, xytext=(3, 3),
                                textcoords="offset points")
        _style(ax, title=f"scenario: {scenario}",
               xlabel="avg headroom (MiB) — lower is cheaper",
               ylabel="OOM + demand-above-limit events — lower is safer")
    axes[-1].legend(fontsize=7, framealpha=0.9)
    fig.suptitle("Safety vs efficiency trade-off by controller mode", fontsize=11)
    _save(fig, out_path)


def fig_per_workload(heldout_report: dict, models: list[tuple[str, str]],
                     out_path: Path):
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    rows = [next(r for r in heldout_report["summary"]
                 if r["model"] == m and r["variant"] == v)
            for m, v in models]
    workloads = sorted({wl for r in rows for wl in r.get("per_workload", {})})
    fig, ax = plt.subplots(figsize=(8.5, 4.2))
    width = 0.8 / len(rows)
    for j, row in enumerate(rows):
        xs = [i + j * width for i in range(len(workloads))]
        ys = [row["per_workload"].get(wl, {}).get("mae_mib", np.nan)
              for wl in workloads]
        variant = row["variant"]
        color = (C_BASELINE if variant == "n/a"
                 else C_WITH_PSI if variant == "with_psi" else C_NO_PSI)
        hatch = "//" if row["model"] == "xgb" else None
        ax.bar(xs, ys, width=width, color=color, hatch=hatch,
               edgecolor="white", linewidth=0.5,
               label=f"{row['model']}/{variant}")
    ax.set_xticks([i + 0.4 - width / 2 for i in range(len(workloads))])
    ax.set_xticklabels(workloads, fontsize=8)
    ax.set_yscale("log")
    _style(ax, title="Held-out test MAE per workload (log scale)",
           ylabel="MAE (MiB, log)")
    ax.legend(fontsize=7, framealpha=0.9)
    _save(fig, out_path)


def fig_generalization(heldout_report: dict, shift_report: dict,
                       lowo_report: dict, out_path: Path):
    """MAE under increasing difficulty: held-out runs -> param shift -> LOWO."""
    import matplotlib

    matplotlib.use("Agg")
    import matplotlib.pyplot as plt

    settings = ["held-out runs", "parameter shift", "leave-one-workload-out"]

    def mae_for(model, variant):
        held = next(r["test_mae_across_seeds"]["mean"]
                    for r in heldout_report["summary"]
                    if r["model"] == model and r["variant"] == variant)
        shift = next(r["mae_mib"] for r in shift_report["results"]
                     if r["model"] == model and r["variant"] == variant)
        lowo_vals = [next(res["mae_mib"] for res in fold["results"]
                          if res["model"] == model and res["variant"] == variant)
                     for fold in lowo_report["folds"]]
        return [held, shift, float(np.mean(lowo_vals))]

    fig, ax = plt.subplots(figsize=(7.5, 4.2))
    width = 0.2
    for j, (model, variant, color, hatch) in enumerate((
            ("rf", "no_psi", C_NO_PSI, None),
            ("rf", "with_psi", C_WITH_PSI, None),
            ("xgb", "no_psi", C_NO_PSI, "//"),
            ("xgb", "with_psi", C_WITH_PSI, "//"))):
        xs = [i + j * width for i in range(len(settings))]
        ax.bar(xs, mae_for(model, variant), width=width, color=color,
               hatch=hatch, edgecolor="white", linewidth=0.5,
               label=f"{model}/{variant}")
    ax.set_xticks([i + 1.5 * width for i in range(len(settings))])
    ax.set_xticklabels(settings, fontsize=9)
    _style(ax, title="Generalization: MAE as evaluation difficulty increases",
           ylabel="MAE (MiB)")
    ax.legend(fontsize=8, framealpha=0.9)
    _save(fig, out_path)
